import React, { useCallback, useEffect, useState } from "react";
import ProductList from "../components/ProductList";
import SearchBar from "../components/SearchBar";
import {
  getProducts,
  getProductsSortedByPrice,
  searchProducts
} from "../services/api";

function ProductsPage() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [searchActive, setSearchActive] = useState(false);

  const loadDefault = useCallback(async () => {
    setLoading(true);
    setError("");
    setSearchActive(false);
    try {
      const data = await getProducts();
      setProducts(Array.isArray(data) ? data : []);
    } catch (err) {
      setError(err.message || "Failed to load products.");
      setProducts([]);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadDefault();
  }, [loadDefault]);

  async function sortByPrice(order) {
    setLoading(true);
    setError("");
    setSearchActive(false);
    try {
      const data = await getProductsSortedByPrice(order);
      setProducts(Array.isArray(data) ? data : []);
    } catch (err) {
      setError(err.message || "Failed to sort products.");
    } finally {
      setLoading(false);
    }
  }

  async function handleSearch(keyword) {
    setError("");
    if (!keyword) {
      await loadDefault();
      return;
    }
    setLoading(true);
    setSearchActive(true);
    try {
      const data = await searchProducts(keyword);
      setProducts(Array.isArray(data) ? data : []);
    } catch (err) {
      setError(err.message || "Search failed.");
      setProducts([]);
    } finally {
      setLoading(false);
    }
  }

  return (
    <section className="products-page">
      <h1>Products</h1>

      <SearchBar onSearch={handleSearch} disabled={loading} />

      <div className="sort-toolbar">
        <button
          type="button"
          className="btn-sort"
          onClick={() => sortByPrice("asc")}
          disabled={loading}
        >
          Sort Price ↑
        </button>
        <button
          type="button"
          className="btn-sort"
          onClick={() => sortByPrice("desc")}
          disabled={loading}
        >
          Sort Price ↓
        </button>
      </div>

      {error ? (
        <p className="error-text" role="alert">
          {error}
        </p>
      ) : null}

      <ProductList
        products={products}
        loading={loading}
        emptyMessage={
          searchActive ? "No products match your search." : "No products yet."
        }
      />
    </section>
  );
}

export default ProductsPage;
